const batch = msg.payload;

if (batch && Array.isArray(batch.messages) && batch.messages.length > 0) {
      const first = batch.messages[0];

      if (first) {
            if (Array.isArray(first.readings) && first.readings.length > 0) {
                  first.readings[0].value = 56;
            }
            else if ('value' in first) {
                  first.value = 56;
            }
      }
}

return msg;
